class Editor:
    def __init__(
        self,
        editor: str | None = None,
        env: cabc.Mapping[str, str] | None = None,
        require_save: bool = True,
        extension: str = ".txt",
        process_priority: str | None = None,
    ) -> None:
        self.editor = editor
        self.env = env
        self.require_save = require_save
        self.extension = extension
        self.process_priority = (
            process_priority if process_priority in _PROCESS_PRIORITIES else None
        )

    def get_editor(self) -> str:
        if self.editor is not None:
            return self.editor
        for key in "VISUAL", "EDITOR":
            rv = os.environ.get(key)
            if rv:
                return rv
        if WIN:
            return "notepad"
        for editor in "sensible-editor", "vim", "nano":
            if os.system(f"which {editor} >/dev/null 2>&1") == 0:
                return editor
        return "vi"

    def _set_process_priority(self, pid: int) -> None:
        if self.process_priority is None:
            return

        try:
            if WIN:
                import ctypes

                priority_classes = {
                    "low": 0x00000040,  # IDLE_PRIORITY_CLASS
                    "below_normal": 0x00004000,  # BELOW_NORMAL_PRIORITY_CLASS
                    "normal": 0x00000020,  # NORMAL_PRIORITY_CLASS
                    "above_normal": 0x00008000,  # ABOVE_NORMAL_PRIORITY_CLASS
                    "high": 0x00000080,  # HIGH_PRIORITY_CLASS
                }
                PROCESS_SET_INFORMATION = 0x0200
                kernel32 = ctypes.windll.kernel32  # type: ignore[attr-defined]
                handle = kernel32.OpenProcess(PROCESS_SET_INFORMATION, False, pid)
                if handle:
                    try:
                        kernel32.SetPriorityClass(
                            handle, priority_classes[self.process_priority]
                        )
                    finally:
                        kernel32.CloseHandle(handle)
            else:
                niceness_map = {
                    "low": 10,
                    "below_normal": 5,
                    "normal": 0,
                    "above_normal": -5,
                    "high": -10,
                }
                os.setpriority(
                    os.PRIO_PROCESS, pid, niceness_map[self.process_priority]
                )
        except (OSError, AttributeError):
            pass

    def edit_files(self, filenames: cabc.Iterable[str]) -> None:
        import subprocess

        editor = self.get_editor()
        environ: dict[str, str] | None = None

        if self.env:
